/**
 * @summary WHOIS lookup for a domain
 */
export const getWhoisLookupUrl = (params: WhoisLookupParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/domains/whois?${stringifiedParams}`
    : `/api/domains/whois`;
};

export const whoisLookup = async (
  params: WhoisLookupParams,
  options?: RequestInit,
): Promise<WhoisResult> => {
  return customFetch<WhoisResult>(getWhoisLookupUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getWhoisLookupQueryKey = (params?: WhoisLookupParams) => {
  return [`/api/domains/whois`, ...(params ? [params] : [])] as const;
};

