/**
 * @summary Search knowledgebase articles
 */
export const getSearchKnowledgebaseUrl = (
  params: SearchKnowledgebaseParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/knowledgebase/search?${stringifiedParams}`
    : `/api/knowledgebase/search`;
};

export const searchKnowledgebase = async (
  params: SearchKnowledgebaseParams,
  options?: RequestInit,
): Promise<KbArticle[]> => {
  return customFetch<KbArticle[]>(getSearchKnowledgebaseUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getSearchKnowledgebaseQueryKey = (
  params?: SearchKnowledgebaseParams,
) => {
  return [`/api/knowledgebase/search`, ...(params ? [params] : [])] as const;
};

